26	  { nasId: "4f1d7e2a-7d5d-4d5f-8b55-0f8efb0d1001", prefix: "NAS_EDGE1" },
27	  { nasId: "9dbd4646-5f4e-4fa0-8f44-1d0dbe6f1002", prefix: "NAS_EDGE2" },
28	];
