38	function loadFileEnv() {
39	  const loaded = {};
40	
41	  for (const relativePath of dotenvPaths) {
42	    const filePath = resolve(relativePath);
43	    if (!existsSync(filePath)) continue;
44	
45	    const content = readFileSync(filePath, "utf8");
46	    for (const rawLine of content.split(/\r?\n/)) {
47	      const line = rawLine.trim();
48	      if (!line || line.startsWith("#")) continue;
49	      const eqIndex = line.indexOf("=");
50	      if (eqIndex <= 0) continue;
51	
52	      const key = line.slice(0, eqIndex).trim();
53	      if (!key || loaded[key] !== undefined) continue;
54	
55	      let value = line.slice(eqIndex + 1).trim();
56	      if (
57	        (value.startsWith('"') && value.endsWith('"'))
58	        || (value.startsWith("'") && value.endsWith("'"))
59	      ) {
60	        value = value.slice(1, -1);
61	      }
62	      loaded[key] = value;
63	    }
64	  }
65	
66	  return loaded;
67	}
68	
69	function loadTargets() {
70	  return DEFAULT_TARGETS.map(({ nasId, prefix }) => ({
71	    nasId: process.env[`${prefix}_NAS_ID`] ?? fileEnv[`${prefix}_NAS_ID`] ?? nasId,
72	    name: prefix.toLowerCase(),
73	    apiUrl: requiredEnv(`${prefix}_API_URL`),
74	    apiSecret: requiredEnv(`${prefix}_API_SECRET`),
75	  }));
76	}
77	
78	async function readBackupLog(target) {
79	  const command = [
80	    "sh -lc",
81	    "'",
82	    "[ -f /host/log/synolog/synobackup.log ] && cat /host/log/synolog/synobackup.log;",
83	    "[ -f /host/log/synolog/synobackup.log.0 ] && cat /host/log/synolog/synobackup.log.0;",
84	    "[ -f /host/log/synobackup.log ] && cat /host/log/synobackup.log;",
85	    "[ -f /host/log/synobackup.log.0 ] && cat /host/log/synobackup.log.0",
86	    "'",
87	  ].join(" ");
88	  const response = await fetch(`${target.apiUrl}/exec`, {
89	    method: "POST",
90	    headers: {
91	      Authorization: `Bearer ${target.apiSecret}`,
92	      "Content-Type": "application/json",
93	    },
94	    body: JSON.stringify({
